INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (1, 'Inception', 2010, 148, 'A skilled thief who steals secrets from deep within the subconscious is offered a chance to have his criminal record erased if he can successfully perform inception.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (2, 'Parasite', 2019, 132, 'A poor family schemes to infiltrate a wealthy household by posing as unrelated skilled workers. Class tension escalates with devastating consequences.', 'South Korea', 'Korean');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (3, 'The Dark Knight', 2008, 152, 'Batman faces the Joker, a criminal mastermind who plunges Gotham City into anarchy and forces the Dark Knight closer to crossing the line between hero and vigilante.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (4, 'Spirited Away', 2001, 125, 'A young girl becomes trapped in a mysterious spirit world and must work in a bathhouse to free herself and her parents.', 'Japan', 'Japanese');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (5, 'The Godfather', 1972, 175, 'The aging patriarch of an organized crime dynasty transfers control to his reluctant youngest son, who transforms into a ruthless mafia boss.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (6, 'Pulp Fiction', 1994, 154, 'Interlocking tales of crime and redemption in Los Angeles unfold through the lives of two hitmen, a boxer, a gangster, and his wife.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (7, 'The Shawshank Redemption', 1994, 142, 'A banker sentenced to life in prison forms an unlikely friendship and orchestrates a decades-long plan to escape.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (8, 'Interstellar', 2014, 169, 'A team of astronauts travels through a wormhole near Saturn in search of a new home for humanity as Earth faces ecological collapse.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (9, 'The Matrix', 1999, 136, 'A computer hacker discovers that reality is a simulated world controlled by machines and joins a rebellion to free humanity.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (10, 'Schindler''s List', 1993, 195, 'A German businessman saves over a thousand Jewish refugees during the Holocaust by employing them in his factories.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (11, 'Forrest Gump', 1994, 142, 'A simple man with a low IQ unwittingly influences several historic events in 20th century America while searching for his childhood sweetheart.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (12, 'Fight Club', 1999, 139, 'An insomniac office worker and a soap salesman form an underground fight club that evolves into something much more dangerous.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (13, 'The Lord of the Rings: The Fellowship of the Ring', 2001, 178, 'A hobbit and a fellowship of heroes embark on a quest to destroy a powerful ring and save Middle-earth from the Dark Lord Sauron.', 'New Zealand', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (14, 'Goodfellas', 1990, 146, 'The rise and fall of a mob associate and his friends in the Italian-American crime syndicate spanning three decades.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (15, 'The Silence of the Lambs', 1991, 118, 'A young FBI trainee seeks the help of an imprisoned cannibalistic serial killer to catch another serial killer on the loose.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (16, 'Gladiator', 2000, 155, 'A betrayed Roman general is reduced to slavery and rises through the ranks of gladiatorial combat to avenge the murder of his family.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (17, 'Amelie', 2001, 122, 'A shy Parisian waitress decides to change the lives of those around her for the better while struggling with her own isolation.', 'France', 'French');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (18, 'City of God', 2002, 130, 'Two boys growing up in a violent neighborhood of Rio de Janeiro take different paths: one becomes a photographer, the other a drug dealer.', 'Brazil', 'Portuguese');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (19, 'The Grand Budapest Hotel', 2014, 99, 'A legendary concierge at a famous European hotel and his trusted lobby boy are framed for murder and must prove their innocence.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (20, 'Mad Max: Fury Road', 2015, 120, 'In a post-apocalyptic wasteland, a woman rebels against a tyrannical ruler with the help of a drifter and a group of female prisoners.', 'Australia', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (21, 'Whiplash', 2014, 106, 'A young jazz drummer enrolls at a cutthroat conservatory where an abusive instructor pushes him beyond his limits.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (22, 'Get Out', 2017, 104, 'A young Black man visits his white girlfriend''s family estate and uncovers a disturbing secret about the community.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (23, 'Coco', 2017, 105, 'A boy who dreams of being a musician journeys to the Land of the Dead to find his great-great-grandfather and uncover his family history.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (24, 'Pan''s Labyrinth', 2006, 118, 'In post-Civil War Spain, a young girl escapes into a dark fairy tale world while her stepfather hunts anti-fascist rebels.', 'Mexico', 'Spanish');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (25, 'No Country for Old Men', 2007, 122, 'A hunter stumbles upon a drug deal gone wrong and takes the money, setting off a violent chain of events involving a relentless killer.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (26, 'The Social Network', 2010, 120, 'The founding of Facebook leads to personal and legal complications for its creator and his former friends.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (27, 'Blade Runner 2049', 2017, 164, 'A young blade runner uncovers a long-buried secret that leads him to track down a former blade runner who has been missing for decades.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (28, 'Everything Everywhere All at Once', 2022, 139, 'A middle-aged Chinese immigrant is swept up in an insane adventure where she must connect with parallel universe versions of herself to save the multiverse.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (29, 'La La Land', 2016, 128, 'A jazz pianist and an aspiring actress fall in love while pursuing their dreams in Los Angeles.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (30, 'The Departed', 2006, 151, 'An undercover cop and a mole in the police attempt to identify each other while infiltrating an Irish gang in Boston.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (31, 'Alien', 1979, 117, 'The crew of a commercial spacecraft encounters a deadly extraterrestrial creature after investigating a distress signal on an uncharted planet.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (32, 'Django Unchained', 2012, 165, 'A freed slave teams up with a German bounty hunter to rescue his wife from a brutal plantation owner in the antebellum South.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (33, 'The Truman Show', 1998, 103, 'A man discovers his entire life is a constructed reality television show broadcast to millions of viewers worldwide.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (34, 'Oldboy', 2003, 120, 'A man imprisoned for 15 years without explanation is suddenly released and given five days to find his captor.', 'South Korea', 'Korean');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (35, 'WALL-E', 2008, 98, 'A lonely waste-collecting robot on a deserted Earth meets a sleek reconnaissance robot and follows her across the galaxy.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (36, 'The Prestige', 2006, 130, 'Two rival magicians in Victorian-era London engage in a bitter competition, each trying to outdo the other with increasingly dangerous tricks.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (37, 'Life Is Beautiful', 1997, 116, 'An Italian Jewish man uses humor and imagination to shield his young son from the horrors of a Nazi concentration camp.', 'Italy', 'Italian');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (38, 'Moonlight', 2016, 111, 'A young Black man growing up in Miami grapples with his identity and sexuality across three defining chapters of his life.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (39, 'Jurassic Park', 1993, 127, 'A theme park showcasing genetically engineered dinosaurs turns deadly when the creatures break free during a security failure.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (40, 'The Shining', 1980, 146, 'A family heads to an isolated hotel for the winter where a sinister presence drives the father into violent madness.', 'USA', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (41, 'Harry Potter and the Sorcerer''s Stone', 2001, 152, 'An orphaned boy discovers he is a wizard on his eleventh birthday and enrolls at Hogwarts School of Witchcraft and Wizardry, where he uncovers the truth about his parents and a dark force seeking to return to power.', 'UK', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (42, '28 Days Later', 2002, 113, 'A man wakes from a coma to find London deserted after a rage-inducing virus decimates the population. He joins a small group of survivors searching for safety.', 'UK', 'English');
INSERT INTO Movie (movie_id, title, release_year, runtime_minutes, synopsis, country_of_origin, language) VALUES (43, 'The King''s Speech', 2010, 118, 'The newly crowned King George VI struggles with a debilitating stammer and enlists the help of an unorthodox speech therapist to find his voice and lead his country through World War II.', 'UK', 'English');
