INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (1, 35, 2, 'A cinematic experience', 'I went in with mixed expectations and came out a bit disappointed. The story was compelling and the cinematography was evocative. I would watch it again in a heartbeat.', 'approved', '2024-12-18 08:46:38');
INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (2, 27, 12, 'Intense from start to finish', 'As a fan of drama films, I found this to be masterful. The director did a fantastic job with the pacing and the performances were genuine. A must-see for any film lover.', 'approved', '2024-05-30 11:08:38');
INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (3, 25, 24, 'Lacks depth and substance', 'I watched this film a while back and I have to say, it was a rollercoaster. The screenplay was top-notch and the overall experience was enjoyable. Definitely worth a watch.', 'pending', '2025-03-21 16:51:26');
INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (4, 3, 23, 'Simply unforgettable', 'The editing carried this film from start to finish. While the ending had its moments, it was the cinematography that truly made this a memorable viewing experience. One of the best I have seen this year.', 'approved', '2024-06-19 04:39:48');
INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (5, 3, 19, 'One of the best this year', 'I watched this film recently and I have to say, it blew me away. The production design was decent and the overall experience was satisfying. I plan to revisit it soon.', 'pending', '2025-08-12 21:13:22');
INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (6, 3, 13, 'Not my cup of tea', 'The editing carried this film from start to finish. While the supporting cast had its moments, it was the acting that truly made this a exceptional viewing experience. Could have been stronger but still worth your time.', 'approved', '2025-07-07 02:33:51');
INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (7, 29, 25, 'A slow burn that pays off', 'This movie surprised me in ways I didn''t expect. The production design alone makes it worth watching, but when combined with the ending, it becomes something truly unique. A must-see for any film lover.', 'approved', '2025-06-23 14:52:25');
INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (8, 28, 39, 'One of the greats', 'This movie fell a bit flat in ways I didn''t expect. The cinematography alone makes it worth watching, but when combined with the supporting cast, it becomes something truly exceptional. Definitely worth a watch.', 'approved', '2026-02-20 22:45:50');
INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (9, 20, 29, 'Best film of the decade', 'I have seen this film five times now and it gets better with each viewing. The attention to detail in the cinematography is nuanced and I always notice something new. A must-see for any film lover.', 'rejected', '2025-04-12 10:23:09');
INSERT INTO Review (review_id, user_id, movie_id, review_title, review_body, moderation_status, review_date) VALUES (10, 28, 18, 'A cinematic experience', 'I watched this film last weekend and I have to say, it exceeded my expectations. The editing was top-notch and the overall experience was satisfying. I would watch it again in a heartbeat.', 'approved', '2024-09-09 10:07:15');
