-- =============================================================
-- Update Movie average_rating from Rating table
-- =============================================================

UPDATE Movie m
SET average_rating = (
    SELECT ROUND(AVG(r.rating_value), 2)
    FROM Rating r
    WHERE r.movie_id = m.movie_id
)
WHERE m.movie_id IN (SELECT DISTINCT movie_id FROM Rating);
